SELECT rv.rev_id , rv.res_id , rv.com_id , rv.emp_id , rv.quantity , rv.status , rv.req_date , rv.remark , rv.updated_at , r.res_name , r.res_code , e.emp_name , d.dept_name FROM reservation rv JOIN resource r ON rv.res_id = r.res_id JOIN employee e ON rv.emp_id = e.emp_id JOIN department d ON e.dept_id = d.dept_id WHERE rv.com_id = #{comId}
AND rv.status = #{status}
ORDER BY rv.rev_id DESC LIMIT #{startRow}, #{pageSize}

SELECT COUNT(*)
FROM reservation rv
WHERE rv.com_id = #{comId}

    AND rv.status = #{status}

SELECT COUNT(*)
FROM reservation
WHERE com_id = #{comId}

    AND status = #{status}
